eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   aboutImage: () => (/* binding */ aboutImage),\n/* harmony export */   footer: () => (/* binding */ footer),\n/* harmony export */   getStaticHeader: () => (/* binding */ getStaticHeader),\n/* harmony export */   getStaticPage: () => (/* binding */ getStaticPage),\n/* harmony export */   header: () => (/* binding */ header),\n/* harmony export */   localize: () => (/* binding */ localize),\n/* harmony export */   portrait: () => (/* binding */ portrait),\n/* harmony export */   speakingImage: () => (/* binding */ speakingImage),\n/* harmony export */   staticPages: () => (/* binding */ staticPages)\n/* harmony export */ });\nconst L = (de, en)=>({\n        _i18n: true,\n        de,\n        en\n    });\nfunction isMarker(value) {\n    return typeof value === 'object' && value !== null && value._i18n === true;\n}\nfunction localize(value, locale) {\n    if (isMarker(value)) return value[locale];\n    if (Array.isArray(value)) return value.map((v)=>localize(v, locale));\n    if (value && typeof value === 'object') {\n        const out = {};\n        for (const [k, v] of Object.entries(value))out[k] = localize(v, locale);\n        return out;\n    }\n    return value;\n}\nconst portrait = {\n    filename: '91e7509c-53a8-49f0-8fab-71b00ebe2eb3.JPG',\n    url: '/media/91e7509c-53a8-49f0-8fab-71b00ebe2eb3.JPG',\n    alt: 'Portrait of Bandar Shanneik',\n    width: 2080,\n    height: 3120\n};\nconst speakingImage = {\n    filename: '10e56e8d-a25f-4063-9974-8d00e1b3529f.JPG',\n    url: '/media/10e56e8d-a25f-4063-9974-8d00e1b3529f.JPG',\n    alt: 'Bandar Shanneik delivering an address at a lectern',\n    width: 2850,\n    height: 1900\n};\nconst aboutImage = {\n    filename: 'af6a4ed9-3dd5-43ec-a6c3-06e3a1342f1f.JPG',\n    url: '/media/af6a4ed9-3dd5-43ec-a6c3-06e3a1342f1f.JPG',\n    alt: 'Bandar Shanneik at the Sheikh Zayed Grand Mosque',\n    width: 2080,\n    height: 3120\n};\n// Header source (markers for localized nav labels).\nconst headerSource = {\n    logoText: 'Bandar Shanneik',\n    showLanguageSwitcher: true,\n    nav: [\n        {\n            link: {\n                label: L('Über mich', 'About'),\n                type: 'internal',\n                page: {\n                    slug: 'about'\n                },\n                variant: 'plain'\n            }\n        },\n        {\n            link: {\n                label: L('Beratung', 'Advisory'),\n                type: 'internal',\n                page: {\n                    slug: 'advisory'\n                },\n                variant: 'plain'\n            }\n        },\n        {\n            link: {\n                label: L('Forschung', 'Research'),\n                type: 'internal',\n                page: {\n                    slug: 'research'\n                },\n                variant: 'plain'\n            }\n        },\n        {\n            link: {\n                label: L('Vorträge', 'Speaking'),\n                type: 'internal',\n                page: {\n                    slug: 'speaking'\n                },\n                variant: 'plain'\n            }\n        },\n        {\n            link: {\n                label: L('Kontakt', 'Contact'),\n                type: 'internal',\n                page: {\n                    slug: 'contact'\n                },\n                variant: 'plain'\n            }\n        }\n    ]\n};\nconst footer = {\n    brandName: 'Bandar Shanneik',\n    tagline: '',\n    columns: [],\n    copyright: ''\n};\n// Publications: real works — titles/venues kept in their original language,\n// only the status flag is localized.\nconst publicationsSource = [\n    {\n        year: '2027',\n        kind: 'peer-reviewed',\n        title: 'Who Counts as a Family in Europe: Polygamous Refugees and the Boundaries of Recognition',\n        venue: 'Journal of Law and Society',\n        status: L('in Vorb.', 'in prep.')\n    },\n    {\n        year: '2026',\n        kind: 'book-chapter',\n        title: 'Forced Divorce: Syrian Refugees and the Act to Combat Child Marriage in Germany',\n        venue: 'Politics of Marriage and Gender: Global Issues in Local Contexts (Rutgers University Press)',\n        status: L('im Druck', 'in print')\n    },\n    {\n        year: '2022',\n        kind: 'legal-article',\n        title: 'Der Immobilienerwerb in den Vereinigten',\n        venue: 'immo aktuell 4(6), 316-320'\n    }\n];\nconst pagesSource = {\n    home: {\n        title: L('Bandar Shanneik', 'Bandar Shanneik'),\n        description: L('Bandar Shanneik — Jurist und Wissenschaftler.', 'Bandar Shanneik — legal expert and academic.'),\n        blocks: [\n            {\n                blockType: 'hero',\n                title: L('Bandar Shanneik', 'Bandar Shanneik'),\n                descriptor: L('Jurist & Akademiker', 'Lawyer & Legal Scholar'),\n                subheading: L('An der Schnittstelle von juristischer Praxis und Wissenschaft – über Deutschland, England und die VAE hinweg.', 'At the intersection of legal practice and academia — across Germany, England and the UAE.'),\n                image: portrait\n            }\n        ]\n    },\n    about: {\n        title: L('Über mich', 'About'),\n        description: L('Bandar Shanneik — zwei parallele Identitäten: juristische Praxis und akademische Forschung.', 'Bandar Shanneik — two parallel identities: legal practice and academic research.'),\n        blocks: [\n            {\n                blockType: 'aboutIntro',\n                image: aboutImage,\n                greeting: L('Hallo, ich bin Bandar.', \"Hi, I'm Bandar.\"),\n                lead: L('Ich bin internationaler Jurist und Rechtswissenschaftler.', 'I am an international lawyer and legal scholar.'),\n                body: L('Seit über einem Jahrzehnt bin ich in der Anwaltspraxis tätig und berate zu grenzüberschreitenden gesellschaftsrechtlichen Fragen in der Golfregion – über civil-law- und common-law-Rechtsordnungen hinweg. In jüngerer Zeit habe ich mich neben der Praxis zunehmend der Wissenschaft zugewandt. Meine Forschung befasst sich mit dem Verhältnis von Recht und seinen Auswirkungen auf Menschen, Kulturen und Gesellschaften.\\n\\nÜber die juristische Welt hinaus begeistere ich mich für interkulturellen Austausch und internationale Beziehungen.', \"I've spent over a decade in private practice advising on cross-border corporate matters across the Gulf region, working across both civil law and common law jurisdictions. More recently, alongside practice, I have increasingly turned towards academia. My research focuses on the relationship between law and its impact on people, cultures, and societies.\\n\\nBeyond the legal world, I'm passionate about cross-cultural exchange and international relations.\"),\n                cvUrl: '#'\n            }\n        ]\n    },\n    advisory: {\n        title: L('Beratung', 'Advisory'),\n        description: L('Rechtsberatung in den Bereichen Gesellschafts- und Handelsrecht, Immobilien, Schiedsverfahren und Governance.', 'Legal advisory across corporate, commercial, real estate, arbitration and governance matters.'),\n        blocks: [\n            {\n                blockType: 'expertise',\n                heading: L('Beratung', 'Advisory'),\n                lead: L('Ich berate Unternehmen, Investoren und Gründer in Rechtsfragen, die Grenzen und Rechtsordnungen überschreiten.', 'I advise companies, investors and entrepreneurs on legal matters that cross borders and jurisdictions.'),\n                intro: L('Ich bin Of Counsel bei Daburon & Partners Legal Consultancy LLP, einer in den VAE ansässigen Kanzlei, die internationale und regionale Mandanten in den Bereichen Gesellschafts-, Handels- und Immobilienrecht sowie Streitbeilegung berät. Mein Schwerpunkt liegt auf grenzüberschreitenden gesellschafts- und handelsrechtlichen Transaktionen, Joint Ventures, Markteintrittsprojekten und internationaler Schiedsgerichtsbarkeit. Ich berate regelmäßig Mandanten, die in der gesamten Golfregion tätig sind, in Angelegenheiten mit mehreren Rechtsordnungen und verbinde dabei civil-law- und common-law-Perspektiven zu wirtschaftlich praxisnahen Lösungen.', 'I am Of Counsel at Daburon & Partners Legal Consultancy LLP, a UAE-based law firm advising international and regional clients on corporate, commercial, real estate, and dispute resolution matters. My work focuses on cross-border corporate and commercial transactions, joint ventures, market entry projects, and international arbitration. I regularly advise clients operating across the Gulf region on matters involving multiple jurisdictions, combining civil law and common law perspectives to provide commercially practical solutions.'),\n                position: {\n                    label: L('Aktuelle Position', 'Current position'),\n                    title: L('Of Counsel', 'Of Counsel'),\n                    firm: L('Daburon & Partners Legal Consultancy LLP', 'Daburon & Partners Legal Consultancy LLP'),\n                    blurb: L('Internationale Kanzlei mit Sitz in den Vereinigten Arabischen Emiraten. Beratung in Unternehmensrecht, Schiedsgerichtsbarkeit und mehr.', 'International law firm based in the United Arab Emirates. Advising on corporate law, arbitration and more.'),\n                    linkUrl: 'https://www.daburon-partners.com/en/home'\n                },\n                jurisdictions: [\n                    {\n                        name: L('Deutschland', 'Germany')\n                    },\n                    {\n                        name: L('England und Wales', 'England and Wales')\n                    },\n                    {\n                        name: L('Vereinigte Arabische Emirate', 'United Arab Emirates')\n                    }\n                ],\n                areas: [\n                    {\n                        title: L('Internationale Schiedsgerichtsbarkeit', 'International Arbitration'),\n                        description: L('Strategische Beratung und Vertretung in grenzüberschreitenden Streitigkeiten in den Bereichen Handel, Bau, Ingenieurwesen und Gesellschaftsrecht.', 'Strategic advice and representation in cross-border commercial, construction, engineering, and corporate disputes.')\n                    },\n                    {\n                        title: L('Gesellschafts- & Handelsrecht', 'Corporate & Commercial'),\n                        description: L('Gesellschaftsrechtliche Strukturierung, Governance, Handelsverträge, Joint Ventures und Markteintrittsprojekte.', 'Corporate structuring, governance, commercial contracts, joint ventures, and market entry projects.')\n                    },\n                    {\n                        title: L('Fusionen & Übernahmen', 'Mergers & Acquisitions'),\n                        description: L('Transaktionsstrukturierung, Due Diligence, Investitionstransaktionen, Erwerbe, Veräußerungen und Restrukturierungen.', 'Transaction structuring, due diligence, investment transactions, acquisitions, disposals, and restructurings.')\n                    },\n                    {\n                        title: L('Venture Capital & Start-ups', 'Venture Capital & Startups'),\n                        description: L('Gründervereinbarungen, Finanzierungsrunden, Gesellschaftervereinbarungen und Transaktionen in der Wachstumsphase.', 'Founder arrangements, investment rounds, shareholder agreements, and growth-stage transactions.')\n                    }\n                ],\n                memberships: [\n                    {\n                        name: L('Deutsche Institution für Schiedsgerichtsbarkeit (DIS)', 'German Arbitration Institute (DIS)')\n                    },\n                    {\n                        name: L('Vienna International Arbitral Centre (VIAC)', 'Vienna International Arbitral Centre (VIAC)')\n                    },\n                    {\n                        name: L('Deutsch-Jordanische Gesellschaft e.V.', 'German Jordanian Society (Deutsch-Jordanische Gesellschaft e.V.)')\n                    },\n                    {\n                        name: L('Deutsch-Arabische Freundschaftsgesellschaft (DAFG)', 'German-Arab Friendship Association (DAFG)')\n                    }\n                ]\n            }\n        ]\n    },\n    research: {\n        title: L('Forschung', 'Research'),\n        description: L('Forschung und Publikationen von Bandar Shanneik.', 'Research and publications by Bandar Shanneik.'),\n        blocks: [\n            {\n                blockType: 'researchIntro',\n                heading: L('Akademische Forschung', 'Academic Research'),\n                position: {\n                    role: L('Research Fellow', 'Research Fellow'),\n                    institution: L('SOAS University of London', 'SOAS University of London'),\n                    project: {\n                        label: 'RELI-GENE',\n                        url: 'https://religene.eu',\n                        note: L('ein vom ERC mit einem Consolidator Grant gefördertes Projekt unter der Leitung von Prof. Yafa Shanneik', 'an ERC Consolidator Grant project led by Prof. Yafa Shanneik')\n                    }\n                },\n                body: L('Meine Forschung untersucht, wie Rechtssysteme Entscheidungen treffen, Normen auslegen und auf gesellschaftlichen und technologischen Wandel reagieren.\\n\\nAusgehend von juristischer Praxis und akademischer Forschung arbeite ich an der Schnittstelle von künstlicher Intelligenz und Recht, vergleichender Rechtswissenschaft, Migrationsrecht und der Anerkennung von Familien. Ein wiederkehrendes Thema meiner Arbeit ist das Zusammenspiel von formalen Rechtsnormen, institutionellen Strukturen und menschlicher Entscheidungsfindung.', 'My research explores how legal systems make decisions, interpret norms and respond to social and technological change.\\n\\nDrawing on both professional legal practice and academic inquiry, I work across the fields of artificial intelligence and law, comparative legal studies, migration law and family recognition. A recurring theme in my work is the interaction between formal legal rules, institutional structures and human decision-making.'),\n                projectBody: L('Als Research Fellow an der SOAS University of London wirke ich am ERC-geförderten Projekt RELI-GENE mit, das das Verhältnis von Religion, Geschlecht und Familienbeziehungen in transnationalen Kontexten untersucht. Meine Forschung befasst sich mit der rechtlichen Behandlung grenzüberschreitender Familienbeziehungen nach deutschem, englischem und emiratischem Recht, mit besonderem Augenmerk auf Anerkennung, Migration und das Zusammenspiel von religiösen Normen und staatlichen Rechtsordnungen.', 'As a Research Fellow at SOAS University of London, I contribute to the ERC-funded RELI-GENE project, which explores the relationship between religion, gender, and family relations in transnational settings. My research examines the legal treatment of cross-border family relationships under German, English, and UAE law, with a particular focus on recognition, migration, and the interaction between religious norms and state legal systems.')\n            },\n            {\n                blockType: 'researchTimeline',\n                heading: L('Ausgewählte Publikationen', 'Selected Publications'),\n                mode: 'manual',\n                manualItems: publicationsSource,\n                compact: true\n            }\n        ]\n    },\n    speaking: {\n        title: L('Vorträge', 'Speaking'),\n        description: L('Vorträge, Workshops, Podiumsdiskussionen und Webinare von Bandar Shanneik zu Recht und Wirtschaft.', 'Talks, workshops, panel discussions and webinars by Bandar Shanneik on law and business.'),\n        blocks: [\n            {\n                blockType: 'speaking',\n                image: speakingImage,\n                heading: L('Vorträge & öffentliches Engagement', 'Speaking & Public Engagement'),\n                intro: L('Ich spreche regelmäßig auf Konferenzen, Wirtschaftsforen, an Universitäten und bei Fachveranstaltungen über rechtliche, regulatorische und politische Entwicklungen, die internationale Wirtschaft und Gesellschaft betreffen.\\n\\nMeine Vorträge verbinden praktische juristische Erfahrung aus dem Nahen Osten mit breiteren akademischen Perspektiven auf Recht, Technologie und gesellschaftlichen Wandel.', 'I regularly speak at conferences, business forums, universities and professional events on legal, regulatory and policy developments affecting international business and society.\\n\\nMy presentations combine practical legal experience from the Middle East with broader academic perspectives on law, technology and social change.'),\n                groups: [\n                    {\n                        title: L('Vorträge & Workshops', 'Legal Presentations & Workshops'),\n                        items: [\n                            {\n                                event: 'German Emirati Joint Council',\n                                location: 'Dubai',\n                                title: 'Market Entry in the UAE',\n                                date: '06.11.2024'\n                            },\n                            {\n                                event: 'German Emirati Joint Council',\n                                location: 'Dubai',\n                                title: 'UAE: Legal Updates 2024',\n                                date: '12.02.2024'\n                            },\n                            {\n                                event: 'German Chamber of Commerce and Industry',\n                                location: L('Deutschland', 'Germany'),\n                                title: 'Market Entry into the United Arab Emirates and the Middle East',\n                                date: '02.2024'\n                            },\n                            {\n                                event: 'Netherlands Business Council',\n                                location: 'Dubai',\n                                title: 'Commercial Contracts in the UAE: Practical Examples and What Really Matters When Drawing Up or Signing Commercial Contracts',\n                                date: '15.03.2023'\n                            },\n                            {\n                                event: 'Austrian Business Council',\n                                location: 'Dubai',\n                                title: 'Commercial Contracts: Litigation or Arbitration? Local Law or Foreign Law? What really matters before entering into a contract',\n                                date: '02.11.2022'\n                            }\n                        ]\n                    },\n                    {\n                        title: L('Podiumsdiskussionen', 'Panel Discussions'),\n                        items: [\n                            {\n                                event: 'MENA Forum Bayern 2025, Chamber of Industry and Commerce',\n                                location: L('München', 'Munich'),\n                                title: 'The MENA Region: Geopolitical Challenges and Economic Opportunities',\n                                date: '22.05.2025'\n                            },\n                            {\n                                event: '27th Arab-German Business Forum, Ghorfa',\n                                location: 'Berlin',\n                                title: 'Beyond Borders: Capitalising on Investment Opportunities in Arab Special & Free Zones',\n                                date: '03.06.2024'\n                            }\n                        ]\n                    },\n                    {\n                        title: L('Online-Webinare', 'Online Webinars'),\n                        items: [\n                            {\n                                event: \"Webinar Series 'Global Law Insights', Rödl\",\n                                location: 'Online',\n                                title: 'Law Insights in Dubai (UAE)',\n                                date: '29.04.2025'\n                            },\n                            {\n                                event: 'German-Saudi Arabian Liaison Office for Economic Affairs (GESALO)',\n                                location: 'Online',\n                                title: \"Navigating Saudi Arabia's Personal Data Protection Law\",\n                                date: '25.02.2025'\n                            }\n                        ]\n                    }\n                ]\n            }\n        ]\n    },\n    contact: {\n        title: L('Kontakt', 'Contact'),\n        description: L('Kontaktieren Sie Bandar Shanneik für Forschungskooperationen oder allgemeine Anfragen.', 'Contact Bandar Shanneik for research collaboration or general enquiries.'),\n        blocks: [\n            {\n                blockType: 'contactForm',\n                heading: L('Kontakt aufnehmen', 'Get in touch'),\n                intro: L('Ich freue mich stets über den Austausch mit Wissenschaftlerinnen und Wissenschaftlern, Juristinnen und Juristen, Studierenden sowie Fachleuten, die sich für Recht, Technologie, internationale Beziehungen und grenzüberschreitende Rechtsfragen interessieren.\\n\\nFür Forschungskooperationen, Vortragsanfragen oder allgemeine Anliegen nehmen Sie gerne über das Kontaktformular oder per E-Mail (siehe unten) Kontakt auf.', 'I am always happy to connect with fellow academics, legal practitioners, students, and professionals interested in law, technology, international affairs, and cross-border legal issues.\\n\\nFor research collaborations, speaking engagements, or general enquiries, please feel free to get in touch via the contact form or at the email below.'),\n                email: 'contact.shanneik@gmail.com',\n                submitLabel: L('Nachricht senden', 'Send message'),\n                successMessage: L('Vielen Dank. Ihre Nachricht ist eingegangen — Bandar wird sich direkt bei Ihnen melden.', 'Thank you. Your message has been received — Bandar will reply directly.'),\n                showSubject: true,\n                professionalNote: {\n                    intro: L('Für berufliche Rechtsangelegenheiten wenden Sie sich bitte an', 'For professional legal matters, please direct enquiries to'),\n                    linkLabel: L('Daburon & Partners', 'Daburon & Partners'),\n                    linkUrl: 'https://daburon-partners.com/en/home',\n                    email: 'bandar@daburon-partners.com'\n                }\n            }\n        ]\n    }\n};\n// Exposed for generateStaticParams (slugs) and the seed (per-locale source).\nconst staticPages = pagesSource;\nconst header = headerSource;\nfunction getStaticPage(locale, slug) {\n    const source = pagesSource[slug];\n    return source ? localize(source, locale) : null;\n}\nfunction getStaticHeader(locale) {\n    return localize(headerSource, locale);\n}\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(rsc)/./src/lib/staticContent.ts\n");

